// Webhook 파라미터 검증
const query = $input.first().json.query || {};
const action = query.action || '';         // 'bid_up', 'bid_down', 'hold'
const productId = query.product_id || '';  // nad- ID
const productName = query.product_name || '';
const changePercent = parseFloat(query.percent) || 0;
const token = query.token || '';
const timestamp = query.ts || '';

// 토큰 검증 (간단 해시)
const crypto = require('crypto');
const expectedToken = crypto.createHash('md5')
  .update(productId + timestamp + 'hanasign_secret')
  .digest('hex').substring(0, 12);

if (token !== expectedToken) {
  return [{ json: { error: true, message: '유효하지 않은 승인 링크입니다.', action: 'reject' } }];
}

// 규칙 검증
if (Math.abs(changePercent) > 30) {
  return [{ json: { error: true, message: '입찰가 변경폭 ±30% 초과. 규칙 위반.', action: 'reject' } }];
}

if (action === 'hold') {
  return [{ json: { error: false, action: 'hold', productId, productName, message: '보류 처리되었습니다.' } }];
}

return [{ json: {
  error: false,
  action: action,
  productId: productId,
  productName: productName,
  changePercent: changePercent,
  timestamp: timestamp,
  message: ''
} }];

const crypto = require('crypto');
const prevData = $('파라미터_검증').first().json;
const setNode = $('변수_설정_P4');
const apiKey = setNode.first().json.naver_api_key;
const secretKey = setNode.first().json.naver_secret_key;
const customerId = setNode.first().json.naver_customer_id;

// 쇼핑검색광고 소재별 입찰가 변경: PUT /ncc/ads/{nccAdId}
const adId = prevData.productId;
const timestamp = Date.now().toString();
const method = 'PUT';
const uri = '/ncc/ads/' + adId;

const message = timestamp + '.' + method + '.' + uri;
const signature = crypto
  .createHmac('sha256', secretKey)
  .update(message)
  .digest('base64');

return [{ json: {
  timestamp, signature, api_key: apiKey, customer_id: customerId,
  adId, uri,
  action: prevData.action,
  changePercent: prevData.changePercent,
  productName: prevData.productName,
} }];

const crypto = require('crypto');
const prev = $('서명_생성_입찰변경').first().json;
const setNode = $('변수_설정_P4');
const secretKey = setNode.first().json.naver_secret_key;

// GET으로 현재 광고그룹 정보 조회
const timestamp = Date.now().toString();
const method = 'GET';
const uri = '/ncc/ads/' + prev.adId;
const message = timestamp + '.' + method + '.' + uri;
const signature = crypto
  .createHmac('sha256', secretKey)
  .update(message)
  .digest('base64');

return [{ json: {
  ...prev,
  get_timestamp: timestamp,
  get_signature: signature,
  get_uri: 'https://api.searchad.naver.com' + uri,
} }];

const crypto = require('crypto');
const adObject = $input.first().json;
const prev = $('서명_생성_입찰변경').first().json;
const setNode = $('변수_설정_P4');
const secretKey = setNode.first().json.naver_secret_key;

const currentBid = (adObject.adAttr && adObject.adAttr.bidAmt) || 0;
const adType = adObject.type || 'SHOPPING_PRODUCT_AD';
const changePercent = prev.changePercent;
const rawNewBid = currentBid * (1 + changePercent / 100);
const newBid = Math.max(70, Math.round(rawNewBid / 10) * 10);

// PUT 서명
const timestamp = Date.now().toString();
const method = 'PUT';
const uri = '/ncc/ads/' + prev.adId;
const message = timestamp + '.' + method + '.' + uri;
const signature = crypto
  .createHmac('sha256', secretKey)
  .update(message)
  .digest('base64');

return [{ json: {
  adId: prev.adId,
  adType: adType,
  productName: prev.productName,
  action: prev.action,
  currentBid: currentBid,
  newBid: newBid,
  changePercent: changePercent,
  put_timestamp: timestamp,
  put_signature: signature,
  api_key: prev.api_key,
  customer_id: prev.customer_id,
  put_url: 'https://api.searchad.naver.com' + uri + '?fields=adAttr',
} }];

const data = $('새입찰가_계산').first().json;
const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
<style>body{font-family:'Noto Sans KR',sans-serif;display:flex;justify-content:center;align-items:center;min-height:100vh;background:#f0f9ff;margin:0}
.card{background:#fff;border-radius:16px;padding:40px;text-align:center;box-shadow:0 4px 24px rgba(0,0,0,0.08);max-width:400px}
h2{color:#166534;margin-bottom:8px} p{color:#64748b;font-size:14px;line-height:1.6}</style></head>
<body><div class="card">
<div style="font-size:48px;margin-bottom:12px">✅</div>
<h2>입찰가 변경 완료</h2>
<p><strong>${data.productName}</strong></p>
<p>${data.currentBid}원 → <strong>${data.newBid}원</strong> (${data.changePercent > 0 ? '+' : ''}${data.changePercent}%)</p>
<p style="color:#94a3b8;font-size:12px;margin-top:16px">하나사인몰 AI 광고 에이전트</p>
