return [{ json: { html } }];

const data = $('파라미터_검증').first().json;
const isHold = data.action === 'hold';
const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
<style>body{font-family:'Noto Sans KR',sans-serif;display:flex;justify-content:center;align-items:center;min-height:100vh;background:${isHold?'#fffbeb':'#fef2f2'};margin:0}
.card{background:#fff;border-radius:16px;padding:40px;text-align:center;box-shadow:0 4px 24px rgba(0,0,0,0.08);max-width:400px}
h2{color:${isHold?'#92400e':'#991b1b'};margin-bottom:8px} p{color:#64748b;font-size:14px;line-height:1.6}</style></head>
<body><div class="card">
<div style="font-size:48px;margin-bottom:12px">${isHold?'⏸️':'❌'}</div>
<h2>${isHold?'보류 처리됨':data.message||'처리 실패'}</h2>
<p>${data.productName||''}</p>
<p style="color:#94a3b8;font-size:12px;margin-top:16px">하나사인몰 AI 광고 에이전트</p>
</div></body></html>`;
return [{ json: { html } }];

// 시트 컬럼명과 동일하게 output 구성 (Map Automatically용)
const calc = $('새입찰가_계산').first().json;
const ts = new Date();
const yyyy = ts.getFullYear();
const mm = String(ts.getMonth() + 1).padStart(2, '0');
const dd = String(ts.getDate()).padStart(2, '0');
const hh = String(ts.getHours()).padStart(2, '0');
const mi = String(ts.getMinutes()).padStart(2, '0');
const ss = String(ts.getSeconds()).padStart(2, '0');
const execId = 'E' + yyyy + mm + dd + hh + mi + ss;
const execTime = yyyy + '-' + mm + '-' + dd + ' ' + hh + ':' + mi + ':' + ss;

return [{ json: {
  "실행ID": execId,
  "제안ID": calc.adId,
  "실행일시": execTime,
  "키워드": calc.productName,
  "변경전": calc.currentBid,
  "변경후": calc.newBid,
  "실행결과": "성공",
  "승인자": "이메일 승인",
  "사후ROAS": "",
  "효과": "",
  "메모": calc.action + ' ' + calc.changePercent + '%'
} }];
